#!/usr/bin/env python3
# -*- coding: utf-8 -*-

from pathlib import Path

TARGET = Path("src/ecom_v51/services/import_service.py")


def replace_once(text: str, old: str, new: str, label: str) -> str:
    count = text.count(old)
    if count == 0:
        raise RuntimeError(f"{label} 替换失败，命中次数=0")
    if count > 1:
        raise RuntimeError(f"{label} 替换失败，命中次数={count}")
    return text.replace(old, new, 1)


def ensure_contains(text: str, needle: str, label: str) -> None:
    if needle not in text:
        raise RuntimeError(f"{label} 校验失败")


def main() -> None:
    if not TARGET.exists():
        raise RuntimeError(f"找不到目标文件: {TARGET}")

    text = TARGET.read_text(encoding="utf-8")

    # already patched guard
    if "CORE_SAFE_NOISE_TOKENS" in text and "ENTITY_KEY_MIN_CONFIDENCE = 0.58" in text:
        print("already patched")
        return

    old_constants = '''    HEADER_SCAN_DEPTH = 20\n    HEADER_PREFERRED_START_RANGE = range(8, 17)\n    DYNAMIC_PATTERNS = [\n        "динамик",\n        "изменени",\n        "change",\n        "delta",\n        "trend",\n        "рост",\n        "снижение",\n    ]\n    GENERIC_HEADER_PIECES = {\n'''
    new_constants = '''    HEADER_SCAN_DEPTH = 20\n    HEADER_PREFERRED_START_RANGE = range(8, 17)\n    PROTECTED_TARGETS = CORE_FIELDS\n    DYNAMIC_PATTERNS = [\n        "динамик",\n        "изменени",\n        "change",\n        "delta",\n        "trend",\n        "рост",\n        "снижение",\n    ]\n    CORE_SAFE_NOISE_TOKENS = {\n        "динамик": "dynamic",\n        "изменени": "dynamic",\n        "trend": "dynamic",\n        "delta": "dynamic",\n        "change": "dynamic",\n        "рост": "dynamic",\n        "снижение": "dynamic",\n        "доля": "share",\n        "share": "share",\n        "процент": "share",\n        "%": "share",\n        "abc": "abc",\n        "abc-анализ": "abc",\n        "рекомендац": "recommendation",\n        "recommend": "recommendation",\n        "建议": "recommendation",\n        "平均时效": "ops_extension",\n        "补货": "ops_extension",\n        "时效": "ops_extension",\n        "оборач": "ops_extension",\n        "доставка": "ops_extension",\n    }\n    MAX_SAMPLE_VALUE_LENGTH = 72\n    MAX_SAMPLE_VALUE_TOKENS = 8\n    ENTITY_KEY_MIN_CONFIDENCE = 0.58\n    GENERIC_HEADER_PIECES = {\n'''
    text = replace_once(text, old_constants, new_constants, "常量区")

    old_ru_rules = '''    RU_PHRASE_CANONICAL_RULES = [\n        (["артикул"], "sku"),\n        (["seller sku"], "sku"),\n        (["offer id"], "sku"),\n        (["показы в поиске", "каталоге"], "impressions_search_catalog"),\n        (["показы", "всего"], "impressions_total"),\n        (["показы"], "impressions_total"),\n        (["посещ", "карточк"], "product_card_visits"),\n        (["переход", "карточк"], "product_card_visits"),\n        (["добав", "корзин"], "add_to_cart_total"),\n        (["заказано на сумму"], "order_amount"),\n        (["сумма заказ"], "order_amount"),\n        (["заказ"], "orders"),\n        (["остат", "склад"], "stock_total"),\n        (["в наличии"], "stock_total"),\n        (["рейтинг"], "rating_value"),\n        (["отзыв"], "review_count"),\n        (["индекс цен"], "price_index_status"),\n        (["средняя позиция", "поиск"], "search_catalog_position_avg"),\n    ]\n'''
    new_ru_rules = '''    RU_PHRASE_CANONICAL_RULES = [\n        (["артикул"], "sku"),\n        (["seller sku"], "sku"),\n        (["offer id"], "sku"),\n        (["показы в поиске", "каталоге"], "impressions_search_catalog"),\n        (["показы", "всего"], "impressions_total"),\n        (["посещ", "карточк"], "product_card_visits"),\n        (["переход", "карточк"], "product_card_visits"),\n        (["добав", "корзин"], "add_to_cart_total"),\n        (["заказано на сумму"], "order_amount"),\n        (["сумма заказ"], "order_amount"),\n        (["остат", "склад"], "stock_total"),\n        (["в наличии"], "stock_total"),\n        (["индекс цен"], "price_index_status"),\n        (["средняя позиция", "поиск"], "search_catalog_position_avg"),\n    ]\n'''
    text = replace_once(text, old_ru_rules, new_ru_rules, "俄语宽规则")

    old_preview = '''    def _preview_values_for_column(\n        self, df: pd.DataFrame, col: Any, limit: int = 3\n    ) -> List[Any]:\n        if col not in df.columns:\n            return []\n\n        selected = df.loc[:, col]\n        values: List[Any] = []\n        if isinstance(selected, pd.DataFrame):\n            for row in selected.head(limit).itertuples(index=False, name=None):\n                for item in row if isinstance(row, tuple) else (row,):\n                    values.append(self._safe_scalar(item))\n                    if len(values) >= limit:\n                        return values[:limit]\n            return values[:limit]\n\n        try:\n            raw_values = selected.head(limit).tolist()\n        except Exception:\n            raw_values = (\n                selected.head(limit).values.tolist()\n                if hasattr(selected.head(limit), "values")\n                else []\n            )\n\n        for item in raw_values:\n            if isinstance(item, list):\n                for nested in item:\n                    values.append(self._safe_scalar(nested))\n                    if len(values) >= limit:\n                        return values[:limit]\n            else:\n                values.append(self._safe_scalar(item))\n                if len(values) >= limit:\n                    return values[:limit]\n        return values[:limit]\n\n'''
    new_preview = '''    @staticmethod\n    def _normalize_preview_text(value: Any) -> str:\n        if value is None:\n            return ""\n        text = str(value).strip()\n        text = re.sub(r"\\s+", " ", text)\n        return text\n\n    def _looks_like_explanatory_text(self, value: Any) -> bool:\n        text = self._normalize_preview_text(value)\n        if not text:\n            return False\n\n        if len(text) > self.MAX_SAMPLE_VALUE_LENGTH:\n            return True\n\n        if text.count(".") >= 2:\n            return True\n\n        comma_count = text.count(",") + text.count("，") + text.count("；") + text.count(";")\n        if comma_count >= 2:\n            return True\n\n        tokens = [x for x in re.split(r"[\\s/|,;:]+", text) if x]\n        if len(tokens) > self.MAX_SAMPLE_VALUE_TOKENS:\n            return True\n\n        return False\n\n    def _detect_core_safe_noise(self, value: Any) -> Optional[str]:\n        text = self._normalize_preview_text(value).lower()\n        if not text:\n            return None\n\n        for token, label in self.CORE_SAFE_NOISE_TOKENS.items():\n            if token in text:\n                return label\n\n        if self._looks_like_explanatory_text(text):\n            return "explanatory_text"\n\n        return None\n\n    def _sanitize_sample_values(self, values: List[Any], limit: int = 3) -> List[Any]:\n        cleaned: List[Any] = []\n        seen: set[str] = set()\n\n        for raw in values or []:\n            scalar = self._safe_scalar(raw)\n            if scalar is None:\n                continue\n\n            if isinstance(scalar, float) and pd.isna(scalar):\n                continue\n\n            if isinstance(scalar, (int, float)) and not isinstance(scalar, bool):\n                text = str(scalar)\n                if text not in seen:\n                    seen.add(text)\n                    cleaned.append(scalar)\n                if len(cleaned) >= limit:\n                    break\n                continue\n\n            text = self._normalize_preview_text(scalar)\n            if not text or text.lower() == "nan":\n                continue\n\n            if self._looks_like_explanatory_text(text):\n                continue\n\n            if text in seen:\n                continue\n\n            seen.add(text)\n            cleaned.append(text)\n\n            if len(cleaned) >= limit:\n                break\n\n        return cleaned\n\n    def _preview_values_for_column(\n        self, df: pd.DataFrame, col: Any, limit: int = 3\n    ) -> List[Any]:\n        if col not in df.columns:\n            return []\n\n        selected = df.loc[:, col]\n        raw_values: List[Any] = []\n\n        if isinstance(selected, pd.DataFrame):\n            for row in selected.head(max(limit * 3, 9)).itertuples(index=False, name=None):\n                for item in row if isinstance(row, tuple) else (row,):\n                    raw_values.append(self._safe_scalar(item))\n                    if len(raw_values) >= max(limit * 4, 12):\n                        return self._sanitize_sample_values(raw_values, limit=limit)\n            return self._sanitize_sample_values(raw_values, limit=limit)\n\n        try:\n            source = selected.head(max(limit * 3, 9)).tolist()\n        except Exception:\n            source = (\n                selected.head(max(limit * 3, 9)).values.tolist()\n                if hasattr(selected.head(max(limit * 3, 9)), "values")\n                else []\n            )\n\n        for item in source:\n            if isinstance(item, list):\n                for nested in item:\n                    raw_values.append(self._safe_scalar(nested))\n            else:\n                raw_values.append(self._safe_scalar(item))\n\n            if len(raw_values) >= max(limit * 4, 12):\n                break\n\n        return self._sanitize_sample_values(raw_values, limit=limit)\n\n'''
    text = replace_once(text, old_preview, new_preview, "样本值预览")

    old_score = '''    def _score_entity_key_candidate(self, text: str) -> float:\n        raw = str(text or "").strip()\n        if not raw:\n            return 0.0\n\n        score = 0.0\n        lower = raw.lower()\n        if any(hint in lower for hint in self.ENTITY_KEY_HEADER_HINTS):\n            score += 0.35\n\n        token = self._extract_entity_key_token(raw)\n        if token:\n            score += 0.45\n            if "-" in token or "_" in token:\n                score += 0.1\n            elif token.isdigit() and 8 <= len(token) <= 14:\n                score += 0.05\n\n        if raw.startswith("Unnamed:") or raw.startswith("col_"):\n            score -= 0.15\n\n        return round(max(score, 0.0), 4)\n\n'''
    new_score = '''    def _score_entity_key_candidate(self, text: str) -> float:\n        raw = str(text or "").strip()\n        if not raw:\n            return 0.0\n\n        score = 0.0\n        lower = raw.lower()\n        if any(hint in lower for hint in self.ENTITY_KEY_HEADER_HINTS):\n            score += 0.35\n\n        token = self._extract_entity_key_token(raw)\n        if token:\n            score += 0.45\n            if "-" in token or "_" in token:\n                score += 0.1\n            elif token.isdigit() and 8 <= len(token) <= 14:\n                score += 0.05\n\n        if self._detect_core_safe_noise(raw):\n            score -= 0.35\n\n        if self._looks_like_explanatory_text(raw):\n            score -= 0.4\n\n        if raw.startswith("Unnamed:") or raw.startswith("col_"):\n            score -= 0.15\n\n        return round(max(score, 0.0), 4)\n\n'''
    text = replace_once(text, old_score, new_score, "entity-key 打分")

    old_probe = '''    def _collect_entity_key_probe_values(\n        self,\n        df: pd.DataFrame,\n        field_mappings: List[dict],\n        limit: int = 12,\n    ) -> List[tuple[str, str]]:\n        values: List[tuple[str, str]] = []\n        unmapped_headers = []\n        for item in field_mappings or []:\n            if item.get("standardField") or item.get("dynamicCompanion"):\n                continue\n            original_field = str(item.get("originalField") or "")\n            if original_field:\n                unmapped_headers.append(original_field)\n\n        preferred_headers = []\n        fallback_headers = []\n        for header in unmapped_headers:\n            lower = header.lower()\n            if (\n                header.startswith("Unnamed:")\n                or header.startswith("col_")\n                or "sku" in lower\n                or "货号" in header\n                or "编码" in header\n                or "id" in lower\n                or "артикул" in lower\n            ):\n                preferred_headers.append(header)\n            else:\n                fallback_headers.append(header)\n\n        scan_headers = preferred_headers + fallback_headers\n        for header in scan_headers:\n            if header not in df.columns:\n                continue\n\n            series = df[header]\n            for raw in series.tolist():\n                if raw is None:\n                    continue\n                text = str(raw).strip()\n                if not text or text.lower() == "nan":\n                    continue\n                values.append((header, text))\n                if len(values) >= limit:\n                    return values\n        return values\n\n'''
    new_probe = '''    def _collect_entity_key_probe_values(\n        self,\n        df: pd.DataFrame,\n        field_mappings: List[dict],\n        limit: int = 12,\n    ) -> List[tuple[str, str]]:\n        values: List[tuple[str, str]] = []\n        unmapped_headers = []\n        for item in field_mappings or []:\n            if item.get("standardField") or item.get("dynamicCompanion"):\n                continue\n            original_field = str(item.get("originalField") or "")\n            if original_field:\n                unmapped_headers.append(original_field)\n\n        preferred_headers = []\n        fallback_headers = []\n        for header in unmapped_headers:\n            lower = header.lower()\n\n            if self._detect_core_safe_noise(header):\n                continue\n\n            if (\n                header.startswith("Unnamed:")\n                or header.startswith("col_")\n                or "sku" in lower\n                or "货号" in header\n                or "编码" in header\n                or "id" in lower\n                or "артикул" in lower\n            ):\n                preferred_headers.append(header)\n            else:\n                fallback_headers.append(header)\n\n        scan_headers = preferred_headers + fallback_headers\n        for header in scan_headers:\n            if header not in df.columns:\n                continue\n\n            series = df[header]\n            for raw in series.tolist():\n                if raw is None:\n                    continue\n                text = str(raw).strip()\n                if not text or text.lower() == "nan":\n                    continue\n\n                if self._detect_core_safe_noise(text):\n                    continue\n\n                token = self._extract_entity_key_token(text)\n                if token:\n                    values.append((header, token))\n                elif not self._looks_like_explanatory_text(text) and len(text) <= 48:\n                    values.append((header, text))\n\n                if len(values) >= limit:\n                    return values\n        return values\n\n'''
    text = replace_once(text, old_probe, new_probe, "entity-key 探针")

    # sampleValues candidate pool cleanup
    old_sample_loop = '''            for value in item.get("sampleValues") or []:\n                candidate_pool.append(\n                    ("fieldMappings.sampleValues", original_field or None, str(value))\n                )\n'''
    new_sample_loop = '''            for value in self._sanitize_sample_values(item.get("sampleValues") or [], limit=3):\n                candidate_pool.append(\n                    ("fieldMappings.sampleValues", original_field or None, str(value))\n                )\n'''
    text = replace_once(text, old_sample_loop, new_sample_loop, "suggestion sampleValues")

    old_candidate_loop = '''        for source, column_name, raw in candidate_pool:\n            score = self._score_entity_key_candidate(raw)\n            token = self._extract_entity_key_token(raw)\n'''
    new_candidate_loop = '''        for source, column_name, raw in candidate_pool:\n            if self._detect_core_safe_noise(raw):\n                continue\n\n            score = self._score_entity_key_candidate(raw)\n            token = self._extract_entity_key_token(raw)\n'''
    text = replace_once(text, old_candidate_loop, new_candidate_loop, "suggestion 候选循环")

    text = replace_once(
        text,
        '        if best_score < 0.45:\n',
        '        if best_score < self.ENTITY_KEY_MIN_CONFIDENCE:\n',
        'suggestion 阈值',
    )

    TARGET.write_text(text, encoding="utf-8", newline="\n")

    ensure_contains(text, "CORE_SAFE_NOISE_TOKENS", "新增噪声常量")
    ensure_contains(text, "def _sanitize_sample_values", "新增样本清洗")
    ensure_contains(text, "ENTITY_KEY_MIN_CONFIDENCE = 0.58", "新增阈值")

    print("patched")


if __name__ == "__main__":
    main()
